class Solution:
    def maxWidthOfVerticalArea(self, points):
        xs = [p[0] for p in points]
        n = len(xs)
        for i in range(n):
            for j in range(n - 1 - i):
                if xs[j] > xs[j + 1]:
                    xs[j], xs[j + 1] = xs[j + 1], xs[j]
        best = 0
        for i in range(n - 1):
            gap = xs[i + 1] - xs[i]
            if gap > best:
                best = gap
        return best

