var maxWidthOfVerticalArea = function(points) {
    const xs = points.map(p => p[0]).sort((a, b) => a - b);
    let best = 0;
    for (let i = 0; i + 1 < xs.length; i++) {
        best = Math.max(best, xs[i + 1] - xs[i]);
    }
    return best;
};
